export const effectComponents = [
    { id: 'tilt-card', name: 'Tilt Card', category: 'effects', description: { en: '3D tilt on mouse hover.', tr: 'Fare hover\'da 3D eğilme.', de: '3D-Neigung beim Hover.', fr: 'Inclinaison 3D au survol.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#0a0a0a;border-radius:12px"><div style="width:200px;height:140px;background:linear-gradient(135deg,#ff6b00,#e65100);border-radius:16px;display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700;transform:perspective(600px) rotateX(8deg) rotateY(-8deg);box-shadow:12px 12px 30px rgba(0,0,0,.4)">Tilt Me</div></div>`, html: `<div class="tilt-card">\n  <h3>Tilt Card</h3>\n  <p>Hover over me!</p>\n</div>`, css: `.tilt-card{width:280px;padding:2rem;background:linear-gradient(135deg,#ff6b00,#e65100);border-radius:16px;color:#fff;transition:transform .1s ease;transform-style:preserve-3d;cursor:pointer;box-shadow:0 10px 40px rgba(255,107,0,.2)}`, js: `document.querySelectorAll('.tilt-card').forEach(card=>{\n  card.addEventListener('mousemove',e=>{\n    const r=card.getBoundingClientRect();\n    const x=(e.clientX-r.left)/r.width-.5;\n    const y=(e.clientY-r.top)/r.height-.5;\n    card.style.transform=\`perspective(600px) rotateY(\${x*20}deg) rotateX(\${-y*20}deg)\`;\n  });\n  card.addEventListener('mouseleave',()=>card.style.transform='perspective(600px) rotateY(0) rotateX(0)');\n});` },
    { id: 'cursor-glow', name: 'Cursor Glow', category: 'effects', description: { en: 'Glowing cursor follow effect.', tr: 'Parlayan imleç takip efekti.', de: 'Leuchtender Cursor.', fr: 'Lueur du curseur.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#050505;border-radius:12px;position:relative;overflow:hidden"><div style="position:absolute;width:160px;height:160px;background:radial-gradient(circle,rgba(255,107,0,.35),transparent 70%);border-radius:50%;top:50%;left:50%;transform:translate(-50%,-50%)"></div><span style="color:#888;font-size:14px;position:relative">Move cursor</span></div>`, html: `<div class="cursor-area">\n  <div class="cursor-dot" id="cdot"></div>\n  <p>Move your cursor here</p>\n</div>`, css: `.cursor-area{position:relative;width:100%;height:400px;background:#050505;overflow:hidden;cursor:none}\n.cursor-dot{position:absolute;width:200px;height:200px;border-radius:50%;background:radial-gradient(circle,rgba(255,107,0,.35),transparent 70%);pointer-events:none;transform:translate(-50%,-50%);transition:left .05s,top .05s}`, js: `const a=document.querySelector('.cursor-area'),d=document.getElementById('cdot');\na.addEventListener('mousemove',e=>{const r=a.getBoundingClientRect();d.style.left=e.clientX-r.left+'px';d.style.top=e.clientY-r.top+'px';});` },
    { id: 'magnet-effect', name: 'Magnet Effect', category: 'effects', description: { en: 'Magnetic pull on elements.', tr: 'Elementlere manyetik çekim.', de: 'Magnetischer Anziehungseffekt.', fr: 'Attraction magnétique.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#0a0a0a;border-radius:12px"><div style="width:80px;height:80px;background:linear-gradient(135deg,#ff6b00,#e65100);border-radius:16px;display:flex;align-items:center;justify-content:center;color:#fff;font-size:24px">🧲</div></div>`, html: `<div class="magnet-el" id="magnet">🧲</div>`, css: `.magnet-el{display:inline-flex;width:80px;height:80px;background:linear-gradient(135deg,#ff6b00,#e65100);border-radius:16px;align-items:center;justify-content:center;font-size:2rem;cursor:pointer;transition:transform .2s ease}`, js: `const el=document.getElementById('magnet');\nwindow.addEventListener('mousemove',e=>{\n  const r=el.getBoundingClientRect();\n  const cx=r.left+r.width/2,cy=r.top+r.height/2;\n  const dist=Math.hypot(e.clientX-cx,e.clientY-cy);\n  if(dist<120){\n    el.style.transform=\`translate(\${(e.clientX-cx)*.3}px,\${(e.clientY-cy)*.3}px)\`;\n  }else{\n    el.style.transform='translate(0,0)';\n  }\n});` },
    { id: 'parallax-card', name: 'Parallax Card', category: 'effects', description: { en: 'Card with parallax depth layers.', tr: 'Paralaks derinlik katmanlı kart.', de: 'Paralax-Tiefenschicht-Karte.', fr: 'Carte à couches parallaxes.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#0a0a0a;border-radius:12px"><div style="width:220px;height:160px;background:linear-gradient(135deg,#1a0a00,#0a0a1a);border-radius:16px;position:relative;overflow:hidden;border:1px solid #333"><div style="position:absolute;width:100px;height:100px;background:rgba(255,107,0,.15);border-radius:50%;top:20%;left:20%;filter:blur(20px)"></div><span style="position:absolute;bottom:20px;left:20px;color:#fff;font-weight:700">Parallax</span></div></div>`, html: `<div class="parallax-card" id="pcard">\n  <div class="layer bg-layer"></div>\n  <div class="layer mid-layer">\n    <div class="orb"></div>\n  </div>\n  <div class="layer fg-layer">\n    <h3>Depth</h3>\n  </div>\n</div>`, css: `.parallax-card{position:relative;width:280px;height:180px;border-radius:16px;overflow:hidden;border:1px solid #333;cursor:pointer;transform-style:preserve-3d}\n.layer{position:absolute;inset:0;transition:transform .1s ease}\n.bg-layer{background:linear-gradient(135deg,#1a0a00,#0a0a1a)}\n.orb{position:absolute;width:100px;height:100px;background:rgba(255,107,0,.2);border-radius:50%;filter:blur(24px);top:20%;left:20%}\n.fg-layer{display:flex;align-items:flex-end;padding:20px;color:#fff;font-weight:700}`, js: `const card=document.getElementById('pcard');\ncard.addEventListener('mousemove',e=>{\n  const r=card.getBoundingClientRect();\n  const x=(e.clientX-r.left)/r.width-.5;\n  const y=(e.clientY-r.top)/r.height-.5;\n  card.querySelector('.bg-layer').style.transform=\`translate(\${x*5}px,\${y*5}px)\`;\n  card.querySelector('.mid-layer').style.transform=\`translate(\${x*12}px,\${y*12}px)\`;\n  card.querySelector('.fg-layer').style.transform=\`translate(\${x*20}px,\${y*20}px)\`;\n});\ncard.addEventListener('mouseleave',()=>card.querySelectorAll('.layer').forEach(l=>l.style.transform=''));` },
    { id: 'confetti-effect', name: 'Confetti', category: 'effects', description: { en: 'Click-triggered confetti burst.', tr: 'Tıklamada konfeti patlaması.', de: 'Klick-ausgelöster Konfettiregen.', fr: 'Explosion de confettis au clic.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#0a0a0a;border-radius:12px"><button style="padding:14px 28px;background:#ff6b00;color:#fff;border:none;border-radius:12px;font-weight:700">🎉 Celebrate</button></div>`, html: `<button class="confetti-btn" id="celebrate">🎉 Celebrate</button>`, css: `.confetti-btn{padding:14px 28px;background:#ff6b00;color:#fff;border:none;border-radius:12px;font-weight:700;cursor:pointer;transition:all .2s}\n.confetti-btn:hover{transform:scale(1.05)}\n.confetto{position:fixed;width:8px;height:8px;pointer-events:none;animation:confettiFall 1.5s ease-in forwards;z-index:9999}\n@keyframes confettiFall{0%{transform:translateY(0) rotate(0);opacity:1}100%{transform:translateY(80vh) rotate(720deg);opacity:0}}`, js: `document.getElementById('celebrate').addEventListener('click',e=>{\n  const colors=['#ff6b00','#ffb347','#7c3aed','#3b82f6','#22c55e','#ef4444'];\n  for(let i=0;i<80;i++){\n    const c=document.createElement('div');c.className='confetto';\n    c.style.cssText=\`left:\${e.clientX+Math.random()*100-50}px;top:\${e.clientY-20}px;background:\${colors[Math.floor(Math.random()*colors.length)]};border-radius:\${Math.random()>0.5?'50%':'2px'};animation-delay:\${Math.random()*.5}s;animation-duration:\${1+Math.random()}s\`;\n    document.body.appendChild(c);\n    c.addEventListener('animationend',()=>c.remove());\n  }\n});` },
    { id: 'glass-effect', name: 'Glass Blur', category: 'effects', description: { en: 'Frosted glass blur overlay.', tr: 'Buzlu cam bulanıklık katmanı.', de: 'Milchglas-Überlagerung.', fr: 'Superposition de verre dépoli.' }, preview: () => `<div style="width:100%;height:220px;border-radius:12px;background:linear-gradient(135deg,#ff6b00,#7c3aed);position:relative;overflow:hidden;display:flex;align-items:center;justify-content:center"><div style="position:absolute;width:180px;padding:24px;background:rgba(255,255,255,0.1);backdrop-filter:blur(16px);border-radius:16px;border:1px solid rgba(255,255,255,0.2);text-align:center"><span style="color:#fff;font-weight:700">Glass Effect</span></div></div>`, html: `<div class="glass-overlay">\n  <div class="glass-panel">\n    <h3>Glass Panel</h3>\n    <p>Frosted glass effect</p>\n  </div>\n</div>`, css: `.glass-overlay{position:relative;border-radius:16px;background:linear-gradient(135deg,#ff6b00,#7c3aed);padding:2rem;display:flex;align-items:center;justify-content:center}\n.glass-panel{padding:2rem;background:rgba(255,255,255,.1);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);border-radius:16px;border:1px solid rgba(255,255,255,.2);color:#fff;text-align:center}`, js: `// Pure CSS` },
    { id: 'noise-overlay', name: 'Noise Overlay', category: 'effects', description: { en: 'Animated film grain noise texture.', tr: 'Animasyonlu film tanesi gürültüsü.', de: 'Animierter Filmkorn-Effekt.', fr: 'Texture bruit grain de film.' }, preview: () => `<div style="width:100%;height:220px;border-radius:12px;background:linear-gradient(135deg,#1a0500,#0a0a1a);position:relative;overflow:hidden"><div style="position:absolute;inset:0;opacity:.06;background-image:url('data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22200%22 height=%22200%22><filter id=%22n%22><feTurbulence type=%22fractalNoise%22 baseFrequency=%220.9%22/></filter><rect width=%22200%22 height=%22200%22 filter=%22url(%23n)%22/></svg>');animation:noiseAnim .1s steps(2) infinite"></div><div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700">Noise Texture</div></div>`, html: `<div class="noise-container">\n  <div class="noise-layer"></div>\n  <!-- Your content here -->\n</div>`, css: `.noise-container{position:relative;border-radius:16px;overflow:hidden}\n.noise-layer{position:absolute;inset:0;opacity:.06;background-image:url("data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.9'/></filter><rect width='200' height='200' filter='url(%23n)'/></svg>");animation:noiseAnim .12s steps(3) infinite;pointer-events:none;z-index:1}\n@keyframes noiseAnim{0%{background-position:0 0}25%{background-position:50px 20px}50%{background-position:20px 50px}75%{background-position:80px 30px}100%{background-position:0 0}}`, js: `// Pure CSS` },
    { id: 'mouse-trail', name: 'Mouse Trail', category: 'effects', description: { en: 'Glowing particle mouse trail.', tr: 'Parlayan parçacık fare izi.', de: 'Leuchtende Mausspur.', fr: 'Traînée de souris lumineuse.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#050505;border-radius:12px;position:relative;overflow:hidden"><span style="color:#888;font-size:14px">Move cursor to see trail</span></div>`, html: `<div class="trail-area" id="trail-area"></div>`, css: `.trail-area{position:fixed;inset:0;z-index:0;pointer-events:none}\n.trail-dot{position:fixed;pointerevents:none;border-radius:50%;transform:translate(-50%,-50%);animation:trailFade .6s ease forwards}\n@keyframes trailFade{0%{opacity:1;transform:translate(-50%,-50%) scale(1)}100%{opacity:0;transform:translate(-50%,-50%) scale(0)}}`, js: `document.addEventListener('mousemove',e=>{\n  const dot=document.createElement('div');\n  dot.className='trail-dot';\n  const size=Math.random()*12+4;\n  dot.style.cssText=\`width:\${size}px;height:\${size}px;left:\${e.clientX}px;top:\${e.clientY}px;background:rgba(255,\${Math.floor(Math.random()*100)+50},0,0.7)\`;\n  document.body.appendChild(dot);\n  dot.addEventListener('animationend',()=>dot.remove());\n});` },
    { id: 'card-stack', name: 'Card Stack', category: 'effects', description: { en: 'Hoverable stacked cards.', tr: 'Hover\'lanabilir yığılmış kartlar.', de: 'Überlagerte Karten.', fr: 'Cartes empilées survolables.' }, preview: (t) => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:${t === 'dark' ? '#0a0a0a' : '#f5f5f5'};border-radius:12px"><div style="position:relative;width:180px;height:120px"><div style="position:absolute;width:180px;height:120px;background:#ff6b00;border-radius:14px;transform:rotate(6deg)"></div><div style="position:absolute;width:180px;height:120px;background:#ff9500;border-radius:14px;transform:rotate(3deg)"></div><div style="position:absolute;width:180px;height:120px;background:${t === 'dark' ? '#1a1a1a' : '#fff'};border-radius:14px;border:1px solid ${t === 'dark' ? '#333' : '#e5e5e5'};display:flex;align-items:center;justify-content:center;font-weight:700;color:${t === 'dark' ? '#fff' : '#000'}">Top Card</div></div></div>`, html: `<div class="card-stack">\n  <div class="stacked-card card-3"></div>\n  <div class="stacked-card card-2"></div>\n  <div class="stacked-card card-1">Top Card</div>\n</div>`, css: `.card-stack{position:relative;width:220px;height:140px}\n.stacked-card{position:absolute;width:100%;height:100%;border-radius:16px;transition:transform .3s ease}\n.card-3{background:#ff6b00;transform:rotate(6deg)}\n.card-2{background:#ff9500;transform:rotate(3deg)}\n.card-1{background:#1a1a1a;border:1px solid #333;display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700}\n.card-stack:hover .card-3{transform:rotate(10deg) translate(-20px,10px)}\n.card-stack:hover .card-2{transform:rotate(5deg) translate(-10px,5px)}`, js: `// Pure CSS` },
    { id: 'scroll-progress', name: 'Scroll Progress', category: 'effects', description: { en: 'Page scroll progress bar.', tr: 'Sayfa kaydırma ilerleme çubuğu.', de: 'Seiten-Scroll-Fortschrittsbalken.', fr: 'Barre de progression de défilement.' }, preview: () => `<div style="width:100%;height:220px;background:#0a0a0a;border-radius:12px;position:relative"><div style="position:absolute;top:0;left:0;height:3px;width:65%;background:linear-gradient(90deg,#ff6b00,#ffb347);border-radius:0 999px 999px 0"></div><div style="display:flex;align-items:center;justify-content:center;height:100%;color:#888;font-size:14px">65% scrolled</div></div>`, html: `<div class="scroll-bar" id="scroll-bar"></div>`, css: `.scroll-bar{position:fixed;top:0;left:0;height:3px;width:0%;background:linear-gradient(90deg,#ff6b00,#ffb347);z-index:9999;transition:width .1s ease;border-radius:0 999px 999px 0}`, js: `window.addEventListener('scroll',()=>{\n  const scrolled=(document.documentElement.scrollTop)/(document.documentElement.scrollHeight-window.innerHeight);\n  document.getElementById('scroll-bar').style.width=scrolled*100+'%';\n});` },
    { id: 'image-reveal', name: 'Image Reveal', category: 'effects', description: { en: 'Hover image reveal comparison.', tr: 'Hover resim ortaya çıkarma karşılaştırması.', de: 'Hover-Bildvergleichseffekt.', fr: 'Révélation d\'image au survol.' }, preview: () => `<div style="width:100%;height:220px;border-radius:12px;overflow:hidden;position:relative;cursor:ew-resize"><div style="position:absolute;inset:0;background:linear-gradient(135deg,#ff6b00,#e65100)"></div><div style="position:absolute;inset:0;background:linear-gradient(135deg,#7c3aed,#3b82f6);clip-path:inset(0 50% 0 0)"></div><div style="position:absolute;left:50%;top:0;bottom:0;width:2px;background:#fff"></div></div>`, html: `<div class="compare-wrap" id="compare">\n  <div class="compare-before">Before</div>\n  <div class="compare-after">After</div>\n  <div class="compare-handle"></div>\n</div>`, css: `.compare-wrap{position:relative;overflow:hidden;border-radius:16px;cursor:ew-resize;user-select:none}\n.compare-before,.compare-after{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700}\n.compare-before{background:linear-gradient(135deg,#ff6b00,#e65100)}\n.compare-after{background:linear-gradient(135deg,#7c3aed,#3b82f6);clip-path:inset(0 50% 0 0);transition:clip-path .05s}\n.compare-handle{position:absolute;left:50%;top:0;bottom:0;width:2px;background:#fff;cursor:ew-resize}`, js: `const wrap=document.getElementById('compare');\nlet drag=false;\nwrap.addEventListener('mousedown',()=>drag=true);\nwindow.addEventListener('mouseup',()=>drag=false);\nwindow.addEventListener('mousemove',e=>{\n  if(!drag)return;\n  const r=wrap.getBoundingClientRect();\n  const pct=Math.max(0,Math.min(100,(e.clientX-r.left)/r.width*100));\n  wrap.querySelector('.compare-after').style.clipPath=\`inset(0 \${100-pct}% 0 0)\`;\n  wrap.querySelector('.compare-handle').style.left=pct+'%';\n});` },
    { id: 'reveal-overlay', name: 'Reveal Overlay', category: 'effects', description: { en: 'Sliding color overlay reveal.', tr: 'Kayan renk katmanı açılması.', de: 'Schiebendes Farb-Overlay.', fr: 'Superposition coulissante.' }, preview: () => `<div style="width:100%;height:220px;border-radius:12px;overflow:hidden;position:relative;background:#1a1a1a"><div style="position:absolute;inset:0;background:#ff6b00;animation:curtainSlide 1.5s ease infinite alternate;transform-origin:right;transform:scaleX(0.3)"></div><div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:#fff;font-size:20px;font-weight:700">Hidden Content</div></div>`, html: `<div class="reveal-box">\n  <div class="reveal-curtain"></div>\n  <div class="reveal-content">Hidden Content</div>\n</div>`, css: `.reveal-box{position:relative;overflow:hidden;border-radius:16px}\n.reveal-curtain{position:absolute;inset:0;background:#ff6b00;transform-origin:right;animation:curtainReveal .8s ease .3s forwards}\n@keyframes curtainReveal{from{transform:scaleX(1)}to{transform:scaleX(0)}}\n.reveal-content{padding:2rem;font-size:1.5rem;font-weight:700}`, js: `// Pure CSS` },
    { id: 'text-shadow-3d', name: '3D Text Shadow', category: 'effects', description: { en: 'Layered 3D text shadow effect.', tr: 'Katmanlı 3D metin gölgesi efekti.', de: 'Geschichteter 3D-Textschatten.', fr: 'Ombre de texte 3D en couches.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#050505;border-radius:12px"><span style="font-size:52px;font-weight:900;color:#ff6b00;text-shadow:3px 3px 0 #cc5500,6px 6px 0 #a33d00,9px 9px 0 #7a2b00,12px 12px 16px rgba(0,0,0,.5)">3D</span></div>`, html: `<h1 class="text-3d">3D TEXT</h1>`, css: `.text-3d{font-size:5rem;font-weight:900;color:#ff6b00;text-shadow:3px 3px 0 #cc5500,6px 6px 0 #a33d00,9px 9px 0 #7a2b00,12px 12px 20px rgba(0,0,0,.5);-webkit-text-stroke:1px rgba(0,0,0,.1)}`, js: `// Pure CSS` },
    { id: 'gradient-border', name: 'Gradient Border', category: 'effects', description: { en: 'Animated gradient border effect.', tr: 'Animasyonlu gradyan kenarlık efekti.', de: 'Animierter Verlaufsrahmen.', fr: 'Bordure dégradée animée.' }, preview: (t) => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:${t === 'dark' ? '#0a0a0a' : '#f5f5f5'};border-radius:12px"><div style="width:200px;height:120px;border-radius:16px;background:linear-gradient(135deg,#ff6b00,#7c3aed,#3b82f6);padding:2px"><div style="width:100%;height:100%;border-radius:14px;background:${t === 'dark' ? '#0a0a0a' : '#fff'};display:flex;align-items:center;justify-content:center;font-weight:700;color:${t === 'dark' ? '#fff' : '#000'}">Gradient Border</div></div></div>`, html: `<div class="grad-border-wrap">\n  <div class="grad-border-inner">Content</div>\n</div>`, css: `.grad-border-wrap{padding:2px;border-radius:16px;background:linear-gradient(135deg,#ff6b00,#7c3aed,#3b82f6);background-size:300%;animation:gradientShift 4s ease infinite}\n.grad-border-inner{padding:2rem;border-radius:14px;background:#0a0a0a;color:#fff;font-weight:700}\n@keyframes gradientShift{0%{background-position:0% 50%}50%{background-position:100% 50%}100%{background-position:0% 50%}}`, js: `// Pure CSS` },
    { id: 'hover-spotlight', name: 'Hover Spotlight', category: 'effects', description: { en: 'Grid cards with hover spotlight.', tr: 'Hover projektörlü ızgara kartlar.', de: 'Rasterkarten mit Hover-Scheinwerfer.', fr: 'Cartes grille avec projecteur.' }, preview: (t) => `<div style="width:100%;height:220px;display:flex;gap:8px;padding:16px;background:${t === 'dark' ? '#0a0a0a' : '#f5f5f5'};border-radius:12px">${[1, 2, 3].map(i => `<div style="flex:1;background:${t === 'dark' ? '#141414' : '#fff'};border-radius:10px;border:1px solid ${t === 'dark' ? '#222' : '#e5e5e5'};display:flex;align-items:center;justify-content:center;font-size:13px;color:${t === 'dark' ? '#888' : '#666'}">Card ${i}</div>`).join('')}</div>`, html: `<div class="spotlight-grid" id="sg">\n  <div class="sg-card">Card 1</div>\n  <div class="sg-card">Card 2</div>\n  <div class="sg-card">Card 3</div>\n</div>`, css: `.spotlight-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}\n.sg-card{position:relative;padding:2rem;background:#141414;border:1px solid #222;border-radius:16px;overflow:hidden;cursor:pointer}\n.sg-card::before{content:'';position:absolute;width:300px;height:300px;border-radius:50%;background:radial-gradient(circle,rgba(255,107,0,.15),transparent 70%);transform:translate(-50%,-50%);transition:opacity .3s;opacity:0;pointer-events:none}\n.sg-card:hover::before{opacity:1}`, js: `document.querySelectorAll('.sg-card').forEach(card=>card.addEventListener('mousemove',e=>{\n  const r=card.getBoundingClientRect();\n  const x=e.clientX-r.left,y=e.clientY-r.top;\n  card.style.setProperty('--x',x+'px');card.style.setProperty('--y',y+'px');\n  card.querySelector('::before')||card.style.setProperty('background-position',\`\${x}px \${y}px\`);\n}));` },
    { id: 'glass-morphism', name: 'Glassmorphism', category: 'effects', description: { en: 'Layered glassmorphism composition.', tr: 'Katmanlı cam efekti kompozisyonu.', de: 'Glasmorphismus-Komposition.', fr: 'Composition glassmorphisme.' }, preview: () => `<div style="width:100%;height:220px;border-radius:12px;background:linear-gradient(135deg,#ff6b00 0%,#7c3aed 50%,#3b82f6 100%);position:relative;overflow:hidden"><div style="position:absolute;width:140px;height:140px;border-radius:50%;background:rgba(255,255,255,.2);top:-30px;right:-30px"></div><div style="position:absolute;inset:20px;background:rgba(255,255,255,.1);backdrop-filter:blur(16px);border-radius:10px;border:1px solid rgba(255,255,255,.2);display:flex;align-items:center;justify-content:center;color:#fff;font-weight:700">Glass</div></div>`, html: `<div class="glass-comp">\n  <div class="blob-1"></div>\n  <div class="blob-2"></div>\n  <div class="glass-pane">Glassmorphism</div>\n</div>`, css: `.glass-comp{position:relative;border-radius:16px;background:linear-gradient(135deg,#ff6b00,#7c3aed,#3b82f6);overflow:hidden;min-height:200px;display:flex;align-items:center;justify-content:center}\n.blob-1,.blob-2{position:absolute;border-radius:50%;background:rgba(255,255,255,.2)}\n.blob-1{width:200px;height:200px;top:-50px;right:-50px}\n.blob-2{width:150px;height:150px;bottom:-40px;left:-40px}\n.glass-pane{position:relative;padding:2rem 3rem;background:rgba(255,255,255,.1);backdrop-filter:blur(20px);border-radius:16px;border:1px solid rgba(255,255,255,.2);color:#fff;font-weight:700;font-size:1.2rem}`, js: `// Pure CSS` },
    { id: 'distortion-text', name: 'Distortion', category: 'effects', description: { en: 'SVG feTurbulence distortion on text.', tr: 'SVG feTurbulence metin bozulması.', de: 'SVG-Verzerrungseffekt.', fr: 'Distorsion SVG du texte.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#050505;border-radius:12px"><svg width="300" height="100"><defs><filter id="turb"><feTurbulence type="turbulence" baseFrequency="0.01" numOctaves="3" result="turb"><animate attributeName="baseFrequency" from="0.01" to="0.05" dur="3s" repeatCount="indefinite"/></feTurbulence><feDisplacementMap in="SourceGraphic" in2="turb" scale="20" xChannelSelector="R" yChannelSelector="G"/></filter></defs><text x="50%" y="60%" text-anchor="middle" fill="#ff6b00" font-size="48" font-weight="900" filter="url(#turb)">GLITCH</text></svg></div>`, html: `<svg width="400" height="120">\n  <defs>\n    <filter id="distortion">\n      <feTurbulence type="turbulence" baseFrequency="0.02" numOctaves="3" result="turb">\n        <animate attributeName="baseFrequency" from="0.01" to="0.06" dur="2s" repeatCount="indefinite"/>\n      </feTurbulence>\n      <feDisplacementMap in="SourceGraphic" in2="turb" scale="30" xChannelSelector="R" yChannelSelector="G"/>\n    </filter>\n  </defs>\n  <text x="50%" y="60%" text-anchor="middle" fill="#ff6b00" font-size="48" font-weight="900" filter="url(#distortion)">GLITCH</text>\n</svg>`, css: `/* No CSS needed — pure SVG */`, js: `// Pure SVG animation` },
    { id: 'glow-shadow', name: 'Glow Shadow', category: 'effects', description: { en: 'Colored drop shadow glow effect.', tr: 'Renkli düşme gölgesi parıltı efekti.', de: 'Farbiger Leuchtschatten.', fr: 'Ombre portée colorée.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;gap:20px;background:#050505;border-radius:12px"><div style="width:80px;height:80px;border-radius:50%;background:#ff6b00;box-shadow:0 0 30px rgba(255,107,0,.5),0 0 60px rgba(255,107,0,.3)"></div><div style="width:80px;height:80px;border-radius:16px;background:#7c3aed;box-shadow:0 0 30px rgba(124,58,237,.5),0 0 60px rgba(124,58,237,.3)"></div><div style="width:80px;height:80px;border-radius:12px;background:#3b82f6;box-shadow:0 0 30px rgba(59,130,246,.5),0 0 60px rgba(59,130,246,.3)"></div></div>`, html: `<div class="glow-orange">Orange Glow</div>\n<div class="glow-purple">Purple Glow</div>\n<div class="glow-blue">Blue Glow</div>`, css: `.glow-orange{box-shadow:0 0 30px rgba(255,107,0,.5),0 0 60px rgba(255,107,0,.25);transition:box-shadow .3s}\n.glow-purple{box-shadow:0 0 30px rgba(124,58,237,.5),0 0 60px rgba(124,58,237,.25);transition:box-shadow .3s}\n.glow-blue{box-shadow:0 0 30px rgba(59,130,246,.5),0 0 60px rgba(59,130,246,.25);transition:box-shadow .3s}\n[class^="glow-"]:hover{box-shadow:none}`, js: `// Pure CSS` },
    { id: 'liquid-btn', name: 'Liquid Button', category: 'effects', description: { en: 'Liquid blob hover effect on button.', tr: 'Sıvı blob hover efektli buton.', de: 'Flüssige Blob-Hover-Schaltfläche.', fr: 'Bouton effet blob liquide.' }, preview: () => `<div style="width:100%;height:220px;display:flex;align-items:center;justify-content:center;background:#0a0a0a;border-radius:12px"><button style="padding:16px 36px;background:#ff6b00;color:#fff;border:none;border-radius:30px;font-size:16px;font-weight:700;position:relative;overflow:hidden">Liquid<div style="position:absolute;width:80px;height:80px;background:rgba(255,255,255,0.2);border-radius:50%;top:-20px;right:-20px;animation:float 3s ease-in-out infinite"></div></button></div>`, html: `<button class="liquid-btn">Liquid</button>`, css: `.liquid-btn{position:relative;padding:16px 36px;background:#ff6b00;color:#fff;border:none;border-radius:30px;font-size:1rem;font-weight:700;cursor:pointer;overflow:hidden;transition:all .3s}\n.liquid-btn::before{content:'';position:absolute;width:100px;height:100px;background:rgba(255,255,255,.15);border-radius:50%;top:-30px;left:-30px;transition:all .4s ease}\n.liquid-btn::after{content:'';position:absolute;width:80px;height:80px;background:rgba(255,255,255,.1);border-radius:50%;bottom:-20px;right:-20px;transition:all .4s ease}\n.liquid-btn:hover::before{transform:scale(3)}\n.liquid-btn:hover::after{transform:scale(3)}`, js: `// Pure CSS` },
];
